// Generates docs/problem-names.js from README H1 titles.
const fs = require('fs');
const path = require('path');

const OUT = {};

for (const dir of ['codeforces', 'cses']) {
  OUT[dir] = {};
  if (!fs.existsSync(dir)) continue;

  for (const file of fs.readdirSync(dir).sort()) {
    if (!file.endsWith('.md')) continue;
    const fullPath = path.join(dir, file);
    const md = fs.readFileSync(fullPath, 'utf8');
    const h1 = md.match(/^#\s+(.+?)\s*$/m);
    if (!h1) continue;

    const id = file.replace(/\.md$/, '');
    OUT[dir][id.toUpperCase()] = h1[1].trim();
  }
}

fs.writeFileSync(
  'docs/problem-names.js',
  '// Auto-generated by update-problem-names.js; do not edit manually\n' +
    'window.PROBLEM_NAMES = ' + JSON.stringify(OUT, null, 2) + ';\n'
);

console.log(
  `Generated docs/problem-names.js with ${Object.values(OUT).reduce((sum, group) => sum + Object.keys(group).length, 0)} names`
);
